def solve(*args):
    if not args:
        return None

    # Assuming args is a list of metrics from different instances
    metrics = []
    for arg in args:
        if isinstance(arg, (int, float)):
            metrics.append(arg)

    if not metrics:
        return None

    # Example aggregation: return the average of the metrics
    return sum(metrics) / len(metrics)
